class Solution {
    public boolean canConvertString(String s, String t, int k) {
        if (s.length() != t.length()) return false;
        int[] cnt = new int[26];
        for (int i = 0; i < s.length(); ++i) {
            int diff = (t.charAt(i) - s.charAt(i) + 26) % 26;
            if (diff != 0) cnt[diff]++;
        }
        for (int d = 1; d < 26; ++d) {
            if (cnt[d] == 0) continue;
            int maxMove = d + 26 * (cnt[d] - 1);
            if (maxMove > k) return false;
        }
        return true;
    }
}
```
